VALUES
  ('dietitian-moex-08414', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某教授將進行一項24小時飲食回憶的電話訪問，請問此種調查相較於一般訪員當面訪問調查，其可能的 缺點為何？', '["費時", "成本太高", "隱蔽性較低", "易造成研究誤差"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08415', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '行政院衛生署公布之「市售包裝食品營養標示規範」所定每日營養素攝取量基準值中，脂肪之基準值為：', '["45公克", "55公克", "65公克", "75公克"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08416', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某地方政府規劃進行原住民部落社區營養計畫。若該政府從未進行過任何相關計畫，且不瞭解原住民生 活飲食行為，請問該地方政府在此時適合使用下列何種方法收集資料？', '["網路調查", "郵寄問卷", "電話訪問", "面對面訪問"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08417', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '幼兒在托兒所進餐時受到其他小朋友的影響，開始喜歡進食某些原本不攝取的食物。此同儕影響在 PRECEDE-PROCEED模式中稱為：', '["前傾因素", "促進因素", "增強因素", "影響因素"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08418', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關食品衛生管理法所稱特殊營養食品之敘述，下列何者錯誤？', '["提供特殊營養需求對象食用之配方食品", "包括嬰兒配方食品與較大嬰兒配方輔助食品", "不需經過查驗登記即可輸入販售", "提供特定疾病病人營養需求之病人用食品，必須在醫師、藥師或營養師指導下食用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08419', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '自民國92年以來，台灣地區占食物中毒件數百分比最高之原因為：', '["生、熟食交互感染", "冷藏不足", "熱處理不足", "食物調製後於室溫放置過久"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08420', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '諮商過程中聽到個案說：「我有必要開始控制體重，我需要做一些改變，但我要怎麼吃呢？」。請問此 個案正處於：', '["沈思期（contemplation）", "準備期（preparation）", "行動期（action）", "復發期（relapse）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08421', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'DETERMINE Your Nutritional Health Checklist是由美國膳食營養學會、美國家庭醫學會及國家老化醫學 會所制訂，它是一種：', '["提供老人或其照護者自行填寫的檢查表", "老人生化營養狀況診斷表格", "老人膳食攝取評估表", "醫院臨床營養診斷表格"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08422', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '當營養師詢問個案週末的飲食攝取情況時，個案以一種幾乎聽不到的聲音說話，此種情況屬於非口語行 為的那一種類型？', '["動作學（kinesics）", "空間學（proxemics）", "次語言學（paraliguistics）", "語音學（phonetics）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08423', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某校進行一項體重控制計畫，參加計畫之學童在計畫期間共減少100公斤，該計畫共花費10萬元經費。 該校校長因此計算每減1公斤體重需花費1000元。請問此種評量方式稱為：', '["過程評量（process evaluation）", "全方位評量（goal-free evaluation）", "效能評量（effectiveness evaluation）", "成本效益評量（cost-effective evaluation）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
